];
checks.forEach\(\([num, first, last]\) => {
  const l = d.lines.find\(x => x.number === num\);
  const ok = l.stops[0] === first && l.stops[l.stops.length-1] === last;
  console.log\('Linka ' + num + ': ' + \(ok ? 'OK' : 'CHYBA'\) + 
    ' | ' + l.stops[0] + ' ... ' + l.stops[l.stops.length-1]\);
}\);
")
